#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int X; scanf("%d", &X);
        if(X + 3 <= 10) printf("Yes\n");
        else printf("No\n");
    }
    return 0;
}

